package com.chaobo.scm.supplier.application.integration;
import com.chaobo.scm.common.error.*;import com.chaobo.scm.supplier.application.asn.event.*;import com.chaobo.scm.supplier.application.contract.*;import com.chaobo.scm.supplier.application.finance.*;import com.chaobo.scm.supplier.application.masterdata.*;import com.chaobo.scm.supplier.application.operations.*;import com.chaobo.scm.supplier.application.order.*;import com.chaobo.scm.supplier.application.quality.*;import com.chaobo.scm.supplier.application.returning.*;import com.chaobo.scm.supplier.application.rfq.*;import com.chaobo.scm.supplier.application.score.*;import com.chaobo.scm.supplier.application.shared.*;import org.springframework.stereotype.Service;import tools.jackson.core.JacksonException;import tools.jackson.databind.ObjectMapper;
@Service public class InboundEventReplayApplicationService{private final MasterDataEventConsumeLogPort inbox;private final ObjectMapper json;private final WmsAsnEventConsumerApplicationService wmsAsn;private final TmsAsnEventConsumerApplicationService tmsAsn;private final RfqEventConsumerApplicationService rfq;private final PurchaseOrderEventConsumerApplicationService purchaseOrders;private final QualitySourceEventConsumerApplicationService quality;private final SupplierReturnEventConsumerApplicationService returns;private final BmsFinanceEventConsumerApplicationService finance;private final PerformanceFactEventConsumerApplicationService performance;private final OperationsEventConsumerApplicationService operations;private final ContractApprovalEventConsumerApplicationService approvals;private final MasterDataEventConsumerApplicationService masterData;private final AuditLogRepository audit;public InboundEventReplayApplicationService(MasterDataEventConsumeLogPort inbox,ObjectMapper json,WmsAsnEventConsumerApplicationService wmsAsn,TmsAsnEventConsumerApplicationService tmsAsn,RfqEventConsumerApplicationService rfq,PurchaseOrderEventConsumerApplicationService purchaseOrders,QualitySourceEventConsumerApplicationService quality,SupplierReturnEventConsumerApplicationService returns,BmsFinanceEventConsumerApplicationService finance,PerformanceFactEventConsumerApplicationService performance,OperationsEventConsumerApplicationService operations,ContractApprovalEventConsumerApplicationService approvals,MasterDataEventConsumerApplicationService masterData,AuditLogRepository audit){this.inbox=inbox;this.json=json;this.wmsAsn=wmsAsn;this.tmsAsn=tmsAsn;this.rfq=rfq;this.purchaseOrders=purchaseOrders;this.quality=quality;this.returns=returns;this.finance=finance;this.performance=performance;this.operations=operations;this.approvals=approvals;this.masterData=masterData;this.audit=audit;}public void replay(long id,String reason,CommandContext context){context.requirePermission("supplier:event:replay");if(reason==null||reason.isBlank())throw new BusinessException(ErrorCode.VALIDATION_FAILED,"重放原因不能为空");var event=inbox.findForReplay(id).orElseThrow(()->new BusinessException(ErrorCode.NOT_FOUND,"入站事件不存在"));if(event.status()!=3||event.payloadJson()==null)throw new BusinessException(ErrorCode.STATE_CONFLICT,"只有已保存载荷的失败事件可重放");inbox.markReplayRequested(id,context.operatorId(),reason);dispatch(event);audit.save(context,"REPLAY_INBOUND_EVENT","INBOUND_EVENT",id,event.eventCode(),null,"{\"consumer\":\""+event.consumerName()+"\"}");}private void dispatch(MasterDataEventConsumeLogPort.ReplayEvent event){switch(event.consumerName()){case "supplier-asn-wms"->wmsAsn.consume(read(event,WmsAsnEvent.class));case "supplier-asn-tms"->tmsAsn.consume(read(event,TmsAsnEvent.class));case "supplier-rfq-todo"->rfq.consume(read(event,RfqEvent.class));case PurchaseOrderEventConsumerApplicationService.CONSUMER->purchaseOrders.consume(read(event,PurchaseOrderEvent.class));case "supplier-quality-source"->quality.consume(read(event,QualitySourceEvent.class));case "supplier-return"->returns.consume(read(event,SupplierReturnExternalEvent.class));case "supplier-finance"->finance.consume(read(event,BmsFinanceEvent.class));case "supplier-performance-fact"->performance.consume(read(event,PerformanceFactEvent.class));case "supplier-operations"->operations.consume(read(event,OperationsEvent.class));case ContractApprovalEventConsumerApplicationService.CONSUMER->approvals.consume(read(event,ContractApprovalEvent.class));case MasterDataEventConsumerApplicationService.CONSUMER_NAME->masterData.consume(read(event,MasterDataEvent.class));default->throw new BusinessException(ErrorCode.BUSINESS_RULE_FAILED,"未注册的入站事件消费者: "+event.consumerName());}}private<T>T read(MasterDataEventConsumeLogPort.ReplayEvent event,Class<T> type){try{return json.readValue(event.payloadJson(),type);}catch(JacksonException exception){throw new BusinessException(ErrorCode.VALIDATION_FAILED,"入站事件载荷无法反序列化: "+event.eventCode());}}}
